/**
 * The Gitph axolotl mark. A pink disc carries the mascot as a cream cut-out
 * (the silhouette path is drawn with even-odd fill so the body reads as a hole),
 * with the face features layered on top in ink.
 */
export function LogoMark({ size = 28 }: { size?: number }): React.JSX.Element {
  return (
    <svg
      width={size}
      height={size}
      viewBox="0 0 256 256"
      xmlns="http://www.w3.org/2000/svg"
      role="img"
      aria-label="Gitph"
      className="brand-mark"
    >
      <circle cx="128" cy="120" r="103" fill="var(--brand-cream)" />
      <path d={AXOLOTL_PATH} fill="var(--brand-pink)" fillRule="evenodd" />
      <circle cx="105" cy="119" r="6.5" fill="var(--brand-ink)" />
      <circle cx="151" cy="119" r="6.5" fill="var(--brand-ink)" />
      <path
        d="M114 134 C122 141 134 141 142 134"
        fill="none"
        stroke="var(--brand-ink)"
        strokeWidth="5"
        strokeLinecap="round"
      />
    </svg>
  )
}

interface LogoProps {
  size?: number
  /** Font size of the wordmark; omit to render the mark on its own. */
  wordmark?: number
}

export function Logo({ size = 28, wordmark }: LogoProps): React.JSX.Element {
  return (
    <span className="brand-logo">
      <LogoMark size={size} />
      {wordmark ? (
        <span className="brand-wordmark" style={{ fontSize: wordmark }}>
          Gitph
        </span>
      ) : null}
    </span>
  )
}
